#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
typedef long long LL;
//#define int LL
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
inline void pt(const int &p,const char &ch='\n'){print(p<0?putchar('-'),-p:p);putchar(ch);}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
int n,m;const int N=5e5+10;const LL INFll=1e18;int head[N],des[N<<1],nxt[N<<1],cgt,w[N],deg[N];
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
inline void ins(const int&x,const int &y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;++deg[x];
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;++deg[y];
}
LL dp[N][3],srt[N];//dp[i][0/1/2]--包括父边，父边为w[fa]/w[u]/m 
inline void dfs(int u,int fa=0)
{
	grep(u,i)if(des[i]!=fa)dfs(des[i],u);int r=(deg[u]>>1);
	LL sum=0;int p=0;grep(u,i)if(des[i]!=fa)
	{
		int v=des[i];LL tmp=max(dp[v][0],max(dp[v][1],dp[v][2]));
		sum+=tmp;srt[p++]=tmp-(w[u]<=w[v]?dp[v][0]:max(dp[v][0],dp[v][1]));
	}
	std::sort(srt,srt+p);
	rep(0,r-1,i)sum-=srt[i];LL s1=sum;if(r<p)sum-=srt[r];else sum=-INFll;
	if(u==1){printf("%lld\n",sum);return;}
	dp[u][0]=w[fa]<=w[u]?s1+w[fa]:sum+w[fa];
    dp[u][1]=s1+w[u];dp[u][2]=m<=w[u]?s1+m:sum+m;
}

int main(){n=read();m=read();rep(1,n,i)w[i]=read();rep(2,n,i)ins(read(),read());dfs(1,0);}
